import pandas as pdimport numpy as np  # Добавили Numpy для сверхбыстрого поискаimport matplotlib.pyplot as pltfrom matplotlib.widgets import MultiCursorimport tkinter as tkfrom tkinter import filedialog, ttk, messageboximport osimport jsonPRESETS_FILE = 'log_presets.json'DEFAULT_PRESETS = {    "OpenDiag (Январь 7.2)": {        "TIME": "Время, с",        "RPM": "Скорость вращения двигателя (об/мин)",        "TPS": "Положение дроссельной заслонки (%)",        "UOS": "Угол опережения зажигания (°ПКВ)",        "MAF": "Массовый расход воздуха (кг/час)",        "GBC": "Цикловой расход воздуха (мг/такт)",        "T_WATER": "Температура охлаждающей жидкости (°С)",        "T_AIR": "Температура воздуха на впуске",        "SPEED": "Скорость автомобиля (км/ч)"    }}class MappingDialog:    def __init__(self, parent, columns):        self.top = tk.Toplevel(parent)        self.top.title("Настройка параметров лога")        self.top.geometry("550x600")                self.columns = ["<Не использовать>"] + list(columns)        self.result = None        self.presets = self.load_presets()        frame_preset = ttk.LabelFrame(self.top, text="Пресеты конфигурации")        frame_preset.pack(fill="x", padx=10, pady=5)        self.preset_combo = ttk.Combobox(frame_preset, values=list(self.presets.keys()), state="readonly")        self.preset_combo.pack(side="left", padx=5, pady=5, fill="x", expand=True)        self.preset_combo.bind("<<ComboboxSelected>>", self.apply_preset)        frame_map = ttk.LabelFrame(self.top, text="Укажите, в каких колонках лежат данные:")        frame_map.pack(fill="both", expand=True, padx=10, pady=5)        self.vars = {}        labels = {            "TIME": "Ось времени (Сек):",            "RPM": "Обороты двигателя (RPM):",             "SPEED": "Скорость авто (км/ч):",            "TPS": "Дроссельная заслонка (%):",             "UOS": "Угол опережения зажигания (Град):",             "MAF": "ДМРВ (кг/ч) [Для расчета л.с.]:",             "GBC": "Цикловое наполнение (мг/ц):",            "T_WATER": "Температура ОЖ (°C):",            "T_AIR": "Температура впуска (°C):"        }                for key, text in labels.items():            row = ttk.Frame(frame_map)            row.pack(fill="x", pady=4, padx=5)            ttk.Label(row, text=text, width=32).pack(side="left")            cb = ttk.Combobox(row, values=self.columns, state="readonly", width=35)            cb.set("<Не использовать>")            cb.pack(side="right", fill="x", expand=True)            self.vars[key] = cb        frame_save = ttk.Frame(self.top)        frame_save.pack(fill="x", padx=10, pady=5)        self.new_preset_name = ttk.Entry(frame_save)        self.new_preset_name.pack(side="left", fill="x", expand=True, padx=5)        ttk.Button(frame_save, text="Сохранить как пресет", command=self.save_preset).pack(side="right", padx=5)        ttk.Button(self.top, text="Построить графики", command=self.on_ok).pack(pady=15)        if self.presets:            self.preset_combo.set(list(self.presets.keys())[0])            self.apply_preset()    def load_presets(self):        if os.path.exists(PRESETS_FILE):            try:                with open(PRESETS_FILE, 'r', encoding='utf-8') as f:                    return json.load(f)            except: pass        return DEFAULT_PRESETS.copy()    def save_preset(self):        name = self.new_preset_name.get().strip()        if not name: return        current_mapping = {k: v.get() for k, v in self.vars.items() if v.get() != "<Не использовать>"}        self.presets[name] = current_mapping        with open(PRESETS_FILE, 'w', encoding='utf-8') as f:            json.dump(self.presets, f, ensure_ascii=False, indent=4)        self.preset_combo['values'] = list(self.presets.keys())        self.preset_combo.set(name)        messagebox.showinfo("Успех", f"Пресет '{name}' сохранен!")    def apply_preset(self, event=None):        preset_name = self.preset_combo.get()        if preset_name in self.presets:            mapping = self.presets[preset_name]            for key, cb in self.vars.items():                if key in mapping and mapping[key] in self.columns:                    cb.set(mapping[key])                else:                    cb.set("<Не использовать>")    def on_ok(self):        self.result = {k: v.get() for k, v in self.vars.items() if v.get() != "<Не использовать>"}        self.top.destroy()def clean_data(df):    df.columns = df.columns.str.strip(' "')    for col in df.columns:        clean_series = df[col].astype(str).str.replace('"', '').str.strip().str.replace(',', '.')        df[col] = pd.to_numeric(clean_series, errors='coerce')    return dfdef main():    root = tk.Tk()    root.withdraw()     file_path = filedialog.askopenfilename(        title="Выберите лог",        filetypes=[("Log files", "*.csv *.txt"), ("All files", "*.*")]    )    if not file_path: return    try:        df = pd.read_csv(file_path, sep='\t', engine='python', encoding='cp1251')        if len(df.columns) < 5:            df = pd.read_csv(file_path, sep=';', engine='python', encoding='cp1251')    except Exception as e:        print(f"Ошибка: {e}")        return    df.columns = df.columns.str.strip(' "')    dialog = MappingDialog(root, df.columns)    root.wait_window(dialog.top)        mapping = dialog.result    if not mapping: return    df = clean_data(df)    if 'MAF' in mapping:        df['Calculated_HP'] = df[mapping['MAF']] / 3.0    x_axis = df[mapping['TIME']] if 'TIME' in mapping else df.index        # Конвертируем ось X в Numpy массив для СВЕРХБЫСТРОГО поиска    x_values_np = x_axis.to_numpy()    # ================= НАСТРОЙКА ГРАФИКОВ =================    plt.style.use('dark_background')    fig = plt.figure(figsize=(15, 9))    fig.canvas.manager.set_window_title(f"PRO Анализ лога: {os.path.basename(file_path)}")        gs = fig.add_gridspec(5, 1, left=0.2)    ax1 = fig.add_subplot(gs[0])    ax2 = fig.add_subplot(gs[1], sharex=ax1)    ax3 = fig.add_subplot(gs[2], sharex=ax1)    ax4 = fig.add_subplot(gs[3], sharex=ax1)    ax5 = fig.add_subplot(gs[4], sharex=ax1)    axes_list = [ax1, ax2, ax3, ax4, ax5]    if 'RPM' in mapping: ax1.plot(x_axis, df[mapping['RPM']], color='cyan', label='Обороты (RPM)')    if 'TPS' in mapping:        ax1_2 = ax1.twinx()        ax1_2.plot(x_axis, df[mapping['TPS']], color='red', label='Дроссель (%)', linewidth=2)        ax1_2.set_ylim(0, 105)    ax1.set_title("Обороты и Дроссель", pad=3)    ax1.grid(True, alpha=0.3)    if 'SPEED' in mapping: ax2.plot(x_axis, df[mapping['SPEED']], color='dodgerblue', label='Скорость (км/ч)', linewidth=2)    ax2.set_title("Скорость автомобиля", pad=3)    ax2.grid(True, alpha=0.3)    if 'GBC' in mapping: ax3.plot(x_axis, df[mapping['GBC']], color='orange', label='Наполнение (мг/ц)')    if 'MAF' in mapping:        ax3_2 = ax3.twinx()        ax3_2.plot(x_axis, df['Calculated_HP'], color='lime', label='Мощность (л.с.)', linewidth=2)    ax3.set_title("Дыхание мотора (Воздух и Мощность)", pad=3)    ax3.grid(True, alpha=0.3)    if 'UOS' in mapping: ax4.plot(x_axis, df[mapping['UOS']], color='yellow', label='УОЗ (Град)')    ax4.set_title("Угол Опережения Зажигания", pad=3)    ax4.grid(True, alpha=0.3)    if 'T_WATER' in mapping: ax5.plot(x_axis, df[mapping['T_WATER']], color='magenta', label='Темп. ОЖ (°C)')    if 'T_AIR' in mapping:        ax5_2 = ax5.twinx()        ax5_2.plot(x_axis, df[mapping['T_AIR']], color='pink', label='Темп. Впуска (°C)')    ax5.set_title("Температуры (ОЖ и Впуск)", pad=3)    ax5.grid(True, alpha=0.3)        if 'TIME' in mapping: ax5.set_xlabel("Время (сек)")    # ================= ИНФО-ПАНЕЛЬ =================    text_ax = fig.add_axes([0.01, 0.1, 0.18, 0.8])     text_ax.axis('off')    info_text = text_ax.text(0, 0.5, "Наведите\nмышку\nна графики...", fontsize=12, color='white', verticalalignment='center')    # Включаем blitting для сверхбыстрой отрисовки линии курсора    multi = MultiCursor(fig.canvas, axes_list, color='white', lw=1, horizOn=False, vertOn=True, useblit=True)    # Переменная для хранения последнего индекса (чтобы не перерисовывать текст зря)    last_idx = -1    def on_mouse_move(event):        nonlocal last_idx        if event.inaxes in axes_list and event.xdata is not None:            # Сверхбыстрый бинарный поиск ближайшего значения по оси X            idx = np.searchsorted(x_values_np, event.xdata)            if idx >= len(x_values_np): idx = len(x_values_np) - 1                        # Обновляем текст ТОЛЬКО если мышка перешла на новую строку в логе            if idx != last_idx:                last_idx = idx                txt = f"=== ДАННЫЕ ===\n\n"                if 'TIME' in mapping: txt += f"Время: {df.at[idx, mapping['TIME']]:.1f} с\n\n"                if 'RPM' in mapping: txt += f"Об: {df.at[idx, mapping['RPM']]:.0f} RPM\n"                if 'SPEED' in mapping: txt += f"Скор: {df.at[idx, mapping['SPEED']]:.0f} км/ч\n"                if 'TPS' in mapping: txt += f"Дроссель: {df.at[idx, mapping['TPS']]:.1f} %\n"                txt += "---------------\n"                if 'GBC' in mapping: txt += f"Наполн: {df.at[idx, mapping['GBC']]:.0f} мг/ц\n"                if 'MAF' in mapping: txt += f"Мощн: {df.at[idx, 'Calculated_HP']:.1f} л.с.\n"                txt += "---------------\n"                if 'UOS' in mapping: txt += f"УОЗ: {df.at[idx, mapping['UOS']]:.1f}°\n"                txt += "---------------\n"                if 'T_WATER' in mapping: txt += f"ОЖ: {df.at[idx, mapping['T_WATER']]:.0f}°C\n"                if 'T_AIR' in mapping: txt += f"Впуск: {df.at[idx, mapping['T_AIR']]:.0f}°C"                                info_text.set_text(txt)                fig.canvas.draw_idle()    fig.canvas.mpl_connect('motion_notify_event', on_mouse_move)    plt.tight_layout()    plt.show()if __name__ == "__main__":    main()